SELECT model_number, hardware_version
FROM router_models
WHERE manufacturer_id = 1;

SELECT COUNT(firmware_id) AS download_count
FROM firmware_downloads
WHERE firmware_id = 0;

SELECT DISTINCT u.username
FROM users u
INNER JOIN firmware_downloads fd ON u.user_id = fd.user_id;

SELECT download_date
FROM firmware_downloads
WHERE download_date LIKE '2020-06%';
